/// Fallback verifier that handles archives whose release attests each contained file
/// instead of the archive blob itself.
///
/// Returns `Ok(true)` if every regular file inside the archive is individually
/// attested and verified. Returns `Err(NoAttestations)` if the archive is not
/// an archive or if none of its files have attestations. Returns `Err(Error)`
/// for any verification failure or missing per-file attestation once at least
/// one file has been verified.
async fn verify_archive_per_file_attestations(
    file_path: &Path,
    owner: &str,
    repo_name: &str,
    api_url: &str,
) -> Result<bool, VerificationStatus> {
    let format = TarFormat::from_file_name(
        file_path
            .file_name()
            .and_then(|s| s.to_str())
            .unwrap_or_default(),
    );
    if !format.is_archive() {
        return Err(VerificationStatus::NoAttestations);
    }

    let temp_dir = tempfile::tempdir().map_err(|e| {
        VerificationStatus::Error(format!("failed to create temporary extraction directory: {e}"))
    })?;
    let temp_path = temp_dir.path();
    file::untar(
        file_path,
        temp_path,
        &file::TarOptions {
            format,
            strip_components: 0,
            pr: None,
            preserve_mtime: false,
        },
    )
    .map_err(|e| VerificationStatus::Error(format!("failed to extract archive: {e}")))?;

    let files = collect_regular_files(temp_path);
    if files.is_empty() {
        return Err(VerificationStatus::NoAttestations);
    }

    let mut any_verified = false;
    for file in &files {
        match crate::github::sigstore::verify_attestation(file, owner, repo_name, None, Some(api_url)).await {
            Ok(true) => any_verified = true,
            Ok(false) => {
                return Err(VerificationStatus::Error(format!(
                    "per-file attestation existed but verification returned false for {}",
                    file.display()
                )));
            }
            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                if any_verified {
                    return Err(VerificationStatus::Error(format!(
                        "per-file attestation missing for {} after other files were verified",
                        file.display()
                    )));
                }
                // No attestation for this file and no file has been verified yet;
                // treat the whole archive as not using per-file attestations.
                return Err(VerificationStatus::NoAttestations);
            }
            Err(e) => {
                return Err(VerificationStatus::Error(format!(
                    "per-file attestation verification failed for {}: {e}",
                    file.display()
                )));
            }
        }
    }

    Ok(true)
}
