                Box::pin(crate::github::sigstore::verify_attestation(
                    path,
                    owner,
                    repo_name,
                    None,
                    Some(api_url),
                ))
            })
            .await;
            if let Ok(true) = result {
                ctx.pr.set_message(
                    "✓ per-file GitHub artifact attestations verified".to_string(),
                );
