```rust
fn create_tar_gz(dir: &std::path::Path, entries: &[(&str, &[u8])]) -> std::path::PathBuf {
    let archive_path = dir.join("archive.tar.gz");
    let gz = flate2::write::GzEncoder::new(std::fs::File::create(&archive_path).unwrap(), flate2::Compression::default());
    let mut tar = tar::Builder::new(gz);
    for (name, data) in entries {
        let mut header = tar::Header::new_gnu();
        header.set_size(data.len() as u64);
        header.set_mode(0o644);
        header.set_cksum();
        tar.append_data(&mut header, name, &data[..]).unwrap();
    }
    tar.finish().unwrap();
    archive_path
