    #[test]
    fn test_attestations_supported_custom_api_url() {
        assert!(!attestations_supported("https://ghe.example.com/api/v3"));
        assert!(!attestations_supported("https://gitlab.com/api/v4"));
        assert!(!attestations_supported("https://codeberg.org/api/v1"));
    }

    #[test]
    fn collect_regular_files_ignores_symlinks_and_directories() {
        let dir = tempfile::tempdir().unwrap();
        let regular = dir.path().join("regular");
        std::fs::write(&regular, "content").unwrap();
        let subdir = dir.path().join("subdir");
        std::fs::create_dir(&subdir).unwrap();
        let nested = subdir.join("nested");
        std::fs::write(&nested, "nested").unwrap();
        let link = dir.path().join("link");
        #[cfg(unix)]
        std::os::unix::fs::symlink(&regular, &link).unwrap();
        #[cfg(windows)]
        std::os::windows::fs::symlink_file(&regular, &link).unwrap();

        let files = UnifiedGitBackend::collect_regular_files(dir.path());
        assert_eq!(files.len(), 2);
        assert!(files.contains(&regular));
        assert!(files.contains(&nested));
        assert!(!files.contains(&link));
    }

    fn create_tar_gz(path: &std::path::Path, entries: &[(&str, &[u8])]) -> std::path::PathBuf {
        let file = std::fs::File::create(path).unwrap();
        let gz = flate2::write::GzEncoder::new(file, flate2::Compression::default());
        let mut tar = tar::Builder::new(gz);
        for (name, data) in entries {
            let mut header = tar::Header::new_gnu();
            header.set_size(data.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            tar.append_data(&mut header, name, &data[..]).unwrap();
        }
        tar.finish().unwrap();
        path.to_path_buf()
    }

    #[tokio::test]
    async fn per_file_archive_accepts_all_attested_files() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(
            &dir.path().join("release.tar.gz"),
            &[("bin1", b"hello"), ("bin2", b"world")],
        );
        let calls = Arc::new(Mutex::new(Vec::new()));
        let calls_for_closure = Arc::clone(&calls);
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            move |path| {
                calls_for_closure.lock().unwrap().push(path.to_path_buf());
                Box::pin(async move { Ok(true) })
            },
        )
        .await;
        assert_eq!(result, Ok(true));
        let seen = calls.lock().unwrap();
        assert_eq!(seen.len(), 2);
        assert!(seen.iter().any(|p| p.file_name().unwrap() == "bin1"));
        assert!(seen.iter().any(|p| p.file_name().unwrap() == "bin2"));
    }

    #[tokio::test]
    async fn per_file_archive_rejects_missing_attestation() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(
            &dir.path().join("release.tar.gz"),
            &[("bin1", b"hello"), ("bin2", b"world")],
        );
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            |path| {
                let name = path.file_name().unwrap().to_string_lossy().to_string();
                Box::pin(async move {
                    if name == "bin1" {
                        Ok(true)
                    } else {
                        Err(crate::github::sigstore::AttestationError::NoAttestations)
                    }
                })
            },
        )
        .await;
        let err = result.unwrap_err().to_string();
        assert!(
            err.contains("per-file attestation missing") || err.contains("bin2"),
            "expected fail-closed error about missing attestation, got {err}"
        );
    }

    #[tokio::test]
    async fn per_file_archive_no_attestations_returns_no_attestations() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(
            &dir.path().join("release.tar.gz"),
            &[("bin1", b"hello"), ("bin2", b"world")],
        );
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            |_path| Box::pin(async { Err(crate::github::sigstore::AttestationError::NoAttestations) }),
        )
        .await;
        assert!(matches!(result, Err(VerificationStatus::NoAttestations)));
    }

    #[tokio::test]
    async fn per_file_archive_rejects_verification_failure() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(&dir.path().join("release.tar.gz"), &[("bin1", b"hello")]);
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            |_path| {
                Box::pin(async {
                    Err(crate::github::sigstore::AttestationError::Verification(
                        "signature mismatch".to_string(),
                    ))
                })
            },
        )
        .await;
        let err = result.unwrap_err().to_string();
        assert!(
            err.contains("signature mismatch") && err.contains("bin1"),
            "expected verification failure error, got {err}"
        );
    }

    #[tokio::test]
    async fn per_file_archive_rejects_false_verification() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(&dir.path().join("release.tar.gz"), &[("bin1", b"hello")]);
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            |_path| Box::pin(async { Ok(false) }),
        )
        .await;
        let err = result.unwrap_err().to_string();
        assert!(
            err.contains("verification returned false") && err.contains("bin1"),
            "expected false-verification error, got {err}"
        );
    }

    #[tokio::test]
    async fn per_file_archive_skips_non_archives() {
        let dir = tempfile::tempdir().unwrap();
        let plain = dir.path().join("plain.txt");
        std::fs::write(&plain, "not an archive").unwrap();
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &plain,
            |_path| Box::pin(async { Ok(true) }),
        )
        .await;
        assert!(matches!(result, Err(VerificationStatus::NoAttestations)));
    }

    #[tokio::test]
    async fn per_file_archive_empty_archive_returns_no_attestations() {
        let dir = tempfile::tempdir().unwrap();
        let archive = create_tar_gz(&dir.path().join("release.tar.gz"), &[]);
        let result = UnifiedGitBackend::verify_archive_per_file_attestations(
            &archive,
            |_path| Box::pin(async { Ok(true) }),
        )
        .await;
        assert!(matches!(result, Err(VerificationStatus::NoAttestations)));
    }
}

