/// Fallback verifier for archives whose release attests each contained file
/// instead of the archive blob itself.
///
/// Returns `Ok(true)` only if every regular file inside the archive is
/// individually attested and verified. Returns `Err(NoAttestations)` when the
/// path is not an archive, the archive is empty, or none of its files have any
/// attestation, so the caller can fall through to other verification mechanisms.
/// Returns `Err(Error)` if any file fails verification or if any file is missing
/// an attestation while at least one other file is verified (fail-closed).
async fn verify_archive_per_file_attestations<F>(
    file_path: &std::path::Path,
    verify_file: F,
) -> std::result::Result<bool, VerificationStatus>
where
    F: for<'a> Fn(&'a std::path::Path) -> std::pin::Pin<Box<dyn std::future::Future<Output = std::result::Result<bool, crate::github::sigstore::AttestationError>> + Send + 'a>>,
{
    let filename = file_path
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or_default();
    let format = file::TarFormat::from_file_name(filename);
    if !format.is_archive() {
        return Err(VerificationStatus::NoAttestations);
    }

    let temp_dir = tempfile::tempdir().map_err(|e| {
        VerificationStatus::Error(format!(
            "failed to create temporary extraction directory: {e}"
        ))
    })?;
    let extract_dir = temp_dir.path();
    file::untar(
        file_path,
        extract_dir,
        &file::TarOptions {
            format,
            strip_components: 0,
            pr: None,
            preserve_mtime: false,
        },
    )
    .map_err(|e| {
        VerificationStatus::Error(format!(
            "failed to extract archive for per-file attestation verification: {e}"
        ))
    })?;

    let files = Self::collect_regular_files(extract_dir);
    if files.is_empty() {
        return Err(VerificationStatus::NoAttestations);
    }

    let mut verified_count = 0usize;
    let mut missing_count = 0usize;
    let mut errors = Vec::new();
    for file in &files {
        match verify_file(file).await {
            Ok(true) => verified_count += 1,
            Ok(false) => {
                errors.push(format!(
                    "per-file attestation existed but verification returned false for {}",
                    file.display()
                ));
            }
            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                missing_count += 1;
            }
            Err(e) => {
                errors.push(format!(
                    "per-file attestation verification failed for {}: {e}",
                    file.display()
                ));
            }
        }
    }

    if !errors.is_empty() {
        return Err(VerificationStatus::Error(errors.join("; ")));
    }
    if verified_count == 0 {
        return Err(VerificationStatus::NoAttestations);
    }
    if missing_count > 0 {
        return Err(VerificationStatus::Error(format!(
            "per-file attestation missing for {missing_count} file(s) inside the archive"
        )));
    }
    Ok(true)
}

